import{_ as t,c as r,o as e,ae as l}from"./chunks/framework.z0sZ1NT9.js";const h=JSON.parse('{"title":"AI 相关概念解释","description":"","frontmatter":{},"headers":[],"relativePath":"articles/AI/concepts.md","filePath":"articles/AI/concepts.md"}'),n={name:"articles/AI/concepts.md"};function s(a,o,i,g,c,d){return e(),r("div",null,o[0]||(o[0]=[l('<h1 id="ai-相关概念解释" tabindex="-1">AI 相关概念解释 <a class="header-anchor" href="#ai-相关概念解释" aria-label="Permalink to &quot;AI 相关概念解释&quot;">​</a></h1><h2 id="llm" tabindex="-1">LLM <a class="header-anchor" href="#llm" aria-label="Permalink to &quot;LLM&quot;">​</a></h2><p><strong>大语言模型</strong>（Large Language Model）是基于海量文本数据训练的深度学习模型（通常基于 Transformer 架构，如 GPT-4、Claude 3 等）。</p><ul><li><strong>核心能力</strong>：理解自然语言并生成人类可读的回复，具备强大的通用知识推理、文本总结、翻译、代码编写等能力。</li><li><strong>在 AI 架构中的角色</strong>：通常被视为整个 AI 系统的“大脑”，负责接收指令并进行逻辑推理与决策。</li></ul><h2 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h2><p><strong>智能体</strong>（Agent）是指能够感知环境并自主采取行动以实现特定目标的系统。在当前的语境中，通常是指基于 LLM 构建的 <strong>AI Agent</strong>。</p><ul><li><strong>核心特征</strong>：它不仅能“说话”（生成文本），还能“行动”。通过赋予大模型规划记忆（Memory）、工具调用（Tool Use）和执行反思（Reflection）的能力，Agent 能够自主地完成复杂的多步任务。</li><li><strong>类比</strong>：如果说 LLM 是一个聪明但没有手脚的大脑，那么 Agent 就是包含了大脑、四肢以及工具箱的“数字虚拟员工”。</li></ul><h2 id="mcp" tabindex="-1">MCP <a class="header-anchor" href="#mcp" aria-label="Permalink to &quot;MCP&quot;">​</a></h2><p><strong>模型上下文协议</strong>（Model Context Protocol）是一种标准化的协议架构（由 Anthropic 提出并开源），旨在打破数据孤岛，安全地将 AI 模型与外部数据源和工具连接起来。</p><ul><li><strong>核心作用</strong>：它提供了一个统一的标准，让开发者可以在不同的 AI 智能体和数据源（如本地文件系统、数据库、第三方 API 等）之间建立双向连接。</li><li><strong>架构</strong>：包含 MCP Hosts（如 IDE 或聊天客户端）、MCP Clients（在 Host 内请求数据的组件）和 MCP Servers（暴露具体数据或功能的后端服务）。</li><li><strong>如何通俗地理解 MCP Server</strong>：你可以非常形象地把它理解为一个**“特定能力与工具的合集/路由节点”**。就像传统的 Web 后端微服务，它对外暴露了一组标准的 API（即 Tool），专门负责某一块领域的功能。 <ul><li><strong>典型例子（GitHub MCP Server）</strong>：假设你运行了一个 GitHub 的 MCP Server，这相当于启动了一个本地的微服务。这个 Server 像菜单一样向 AI 声明了自己有 <code>create_issue</code>、<code>search_repo</code>、<code>read_file_from_github</code> 这几个具体的 <strong>Tool</strong>。当 AI 判断需要查阅你远程仓库的代码时，就会发送符合 MCP 协议的请求给这个 Server，Server 再去真正调用真实的 GitHub API 执行动作，并把结果按标准格式返还给 AI。</li></ul></li><li><strong>多 MCP Server 协同（AI 如何知道该调哪个？）</strong>：如果在本地同时连接了 GitHub 服务器、本地文件系统服务器、SQL 数据库服务器等多个 MCP Server，客户端（Host）会向所有的 Server 拉取它们提供的“工具清单”。然后，Host 会把这一大堆 <strong>Tool</strong> 整合在一个全局的说明书里，连同用户的提问一起发送给提供 Function Call 能力的大模型（LLM）。 <ul><li>实际上大模型（LLM）并不知道，也<strong>不需要知道这些工具来源于哪个具体的后端服务</strong>。它只阅读这些被整合提交给它的工具的自然语言描述（比如 <code>read_local_file</code> 和 <code>search_github_repo</code>），根据用户的提问自己推断出应该呼叫哪个工具名字。当 LLM 说出要用 <code>search_github_repo</code> 之后，客户端（Host）自己就清楚这个工具归 GitHub 的节点管，于是把指令直接路由给那个相应的 Server 进程去跑。</li></ul></li><li><strong>通用基座的职责极度简化（通信解耦）</strong>：由于 MCP 的存在，通用基座（如 Claude 客户端或 Cursor）根本不需要关心具体的业务逻辑是如何用代码实现的。这就好比<strong>电脑主板（基座）与 USB 接口（MCP 协议）</strong>：主板厂商不需要自己去造具体的鼠标、键盘或打印机。只要外部设备厂商（社区的 MCP Server）按 USB 标准把设备插上，电脑就能识别出它是个“打印机”。不管打印机内部是怎样进纸、喷墨的，主板只负责无脑地把你想打印的内容通过标准化接口传过去就行了。这样就真正实现了“基座出脑子，社区生态出各行各业的手脚”的万物互联愿景。</li></ul><h2 id="function-call" tabindex="-1">Function Call <a class="header-anchor" href="#function-call" aria-label="Permalink to &quot;Function Call&quot;">​</a></h2><p><strong>函数调用</strong>（Function Calling）是现代大语言模型（如 GPT-4 等）具备的一种核心能力机制。</p><ul><li><strong>核心特征</strong>：它允许开发者在与 LLM 交互时，向模型描述一组预先定义好的函数（即 Tools 的签名和参数表）。模型如果判断需要外部信息来回答问题，会自动输出一段结构化数据（通常是 JSON），指明“请帮我调用 A 函数，并传入 B 和 C 这两个参数”。</li><li><strong>与 Tool 的区别</strong>：Function Call 是模型的<strong>能力与机制</strong>（模型决定“调什么函数并给出参数”），而 Tool 是实际被执行的<strong>具体接口</strong>（外部系统拿到参数后去执行具体代码，再把结果还给模型）。</li></ul><h2 id="tool" tabindex="-1">Tool <a class="header-anchor" href="#tool" aria-label="Permalink to &quot;Tool&quot;">​</a></h2><p><strong>工具</strong>（Tool）是 AI 智能体用来与外部世界交互的具体函数或 API 接口。</p><ul><li><strong>核心作用</strong>：由于原生的大模型本身是静态的且不具备实时获取外部信息或执行操作的能力（比如无法联网、无法直接读写本地文件），“工具”为模型提供了这些能力。</li><li><strong>使用方式</strong>：人类开发者定义工具的用途和参数格式（通常通过 JSON Schema），LLM 会在需要时决定调用哪个工具并生成对应的参数，随后外部环境执行该工具并将结果返回给 LLM，LLM 基于结果继续推理。例如：网络搜索（Web Search）、文件读取（Read File）、执行终端指令等都是典型的 Tool。</li><li><strong>工具过多的挑战与解决（Context 占用问题）</strong>：如果系统中接入了上百个工具，每次提问都把所有工具的详细说明（JSON Schema）全量发送给大模型，会极大地消耗和占用 Context（上下文窗口和 Token），还会导致大模型“挑花眼”反而降低命中准确率。因此在实际的工程落地中： <ul><li><strong>动态检索（RAG for Tools）</strong>：Host 会先将所有工具的功能描述进行向量化存储，当用户提问时，先在本地做一个语义匹配搜索，<strong>只挑出与当前问题最相关的 3~5 个工具</strong>发给大模型做 Function Call 推理。</li><li><strong>多级路由（Multi-Agent Router）</strong>：先用一个轻量级大模型判断用户的意图分类（比如“这是一个关于 GitHub 的问题”），然后仅把该意图类别下的工具加载进来交给大模型执行。</li><li><strong>状态保持与提示词缓存（Prompt Caching）</strong>：由于大模型接口（API）本质上是<strong>无状态的</strong>，这就意味着在多轮对话中，Agent <strong>确实需要每次都把这些工具说明（Schema）重新打包发给 LLM</strong>。为了解决重复传输带来的高昂成本和高延迟，现代前沿模型（如 Claude 3.5、GPT-4o）推出了 <strong>Prompt Caching</strong> 技术。Host 可以将庞大且不变的“工具集说明和系统配置”固定缓存在大模型服务端，后续每轮对话只需要发送新增的用户提问（Query）即可，极大地提升了响应速度并降低了 API 费用。</li></ul></li></ul><h2 id="综合示例-串联-mcp、function-call-与-tool" tabindex="-1">综合示例：串联 MCP、Function Call 与 Tool <a class="header-anchor" href="#综合示例-串联-mcp、function-call-与-tool" aria-label="Permalink to &quot;综合示例：串联 MCP、Function Call 与 Tool&quot;">​</a></h2><p>假设你正在使用一个支持 AI 代码助手的 IDE（比如拥有 MCP 插件的 VS Code），并且你问 AI：“请帮我看看项目根目录下的 <code>package.json</code> 里面写了什么？”</p><p>整个过程是如何流转的？</p><ol><li><strong>MCP 的连接与发现</strong>：AI 助手（作为 MCP Host/Client）启动时，通过 <strong>MCP (模型上下文协议)</strong> 连接到了一个本地文件系统的 MCP Server。这个 Server 将自己拥有的各种能力以标准化的格式声明给 AI 助手，其中就包含了一个名为 <code>read_file</code> 的 <strong>Tool (工具)</strong>。</li><li><strong>LLM 与 Function Call</strong>：AI 助手把你提的问题连同 <code>read_file</code> 的工具说明（基于 JSON Schema 格式）一起发送给云端的 <strong>LLM</strong>（大模型）。在大模型内部推理后，发现自己没法直接读你电脑里的文件，但通过提供的工具列表发现 <code>read_file</code> 可以做到。于是 LLM 触发了 <strong>Function Call (函数调用)</strong> 机制，它没有直接回答文字，而是输出了一段带有指令的结构化数据（如 JSON），意思是：“请帮我调用 <code>read_file</code> 函数，参数是 <code>path=&#39;package.json&#39;</code>”。</li><li><strong>Tool 的实际执行</strong>：AI 助手（在宿主机本地环境）拦截到了这个 Function Call 请求，它并没有让大模型去读文件，而是通过 MCP 协议向本地文件系统 MCP Server 发出调用指令。此时，真正的 <strong>Tool</strong>（一段真实的读取硬盘文件的 Node.js/Python 代码）被执行，读取了 <code>package.json</code> 的文本内容。</li><li><strong>大模型收到结果并回答反馈</strong>：AI 助手把 Tool 拿到的文件内容作为“观察结果 (Observation)”拼接在上下文中重新发回给 LLM。大模型基于文件内容总结后，最终把可读的纯文本回答输出给你。</li></ol><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h2><p><strong>技能</strong>（Skills）通常指赋予 AI 完成特定领域任务的、预先定义好的一组指令（Instructions）、知识和能力的集合。</p><ul><li><strong>核心作用</strong>：与基础的 Tool（通常仅仅是一个执行函数）不同，Skill 更偏向于“行为范式”或“领域知识库”。当给 Agent 装备某个特定领域的 Skill 时，Agent 就掌握了完成该领域任务的最佳实践或专业工作流。</li><li><strong>在系统中的体现</strong>：通常体现为高度定制化的提示词系统（Prompt）、特定的文件操作规范或者组合了多个 Tool 形成的高级功能模块。</li></ul>',23)]))}const C=t(n,[["render",s]]);export{h as __pageData,C as default};
